"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[98],{7116:e=>{e.exports=JSON.parse('{"functions":[],"properties":[{"name":"Frequency","desc":"Frequency band constants. Determines which per-material absorption\\ncoefficients are applied during occlusion.\\n\\n| Value | Typical sounds |\\n|-------|---------------|\\n| `Low` | Explosion rumble, bass, engine idle |\\n| `Mid` | Voice, footsteps, moderate impacts |\\n| `High` | Gunshot crack, glass break, metal ping |\\n\\nHigh-frequency sounds are absorbed far more aggressively by dense\\nmaterials (concrete, brick) than low-frequency ones. A concrete wall that\\nreduces a gunshot crack to near-silence barely dents the pressure wave\\nof an explosion.","lua_type":"{ Low: string, Mid: string, High: string }","source":{"line":37,"path":"docs/SoundTypes.lua"}},{"name":"Preset","desc":"Frozen table of all built-in preset key constants. Use these as arguments\\nto [Resonix:EmitPreset] to avoid typos.\\n\\n```lua\\nEngine:EmitPreset(Resonix.Preset.Gunshot_Rifle, origin, character)\\n```\\n\\n**Built-in presets:**\\n\\n| Key | Intensity | Radius | Frequency |\\n|-----|:---------:|:------:|:---------:|\\n| `Gunshot_Pistol` | 65 | 100 | High |\\n| `Gunshot_Rifle` | 80 | 200 | High |\\n| `Gunshot_Sniper` | 95 | 350 | High |\\n| `Gunshot_Shotgun` | 78 | 150 | Mid |\\n| `Footstep_Walk` | 12 | 25 | Mid |\\n| `Footstep_Sprint` | 22 | 40 | Mid |\\n| `Footstep_Crouch` | 5 | 12 | Mid |\\n| `Impact_Bullet_Hard` | 30 | 50 | High |\\n| `Impact_Bullet_Soft` | 20 | 35 | Mid |\\n| `VendingMachine` | 42 | 65 | Mid |\\n| `PowerNode` | 38 | 55 | Mid |\\n| `PowerFlip` | 70 | 120 | Low |\\n| `Explosion_Grenade` | 88 | 280 | Low |\\n| `Explosion_Large` | 98 | 400 | Low |","lua_type":"{ [string]: string }","source":{"line":70,"path":"docs/SoundTypes.lua"}}],"types":[{"name":"SoundEmission","desc":"Describes a sound event as physical acoustic energy. Stored in [SoundBuffer]\\nand returned in [SoundStimulus.Emission].\\n\\nThe sound system stores `Tag` but never reads it \u2014 it is purely for\\nexternal consumers to classify stimuli after querying.","fields":[{"name":"Id","lua_type":"string","desc":"Unique ID assigned by [Resonix:Emit]."},{"name":"PresetKey","lua_type":"string?","desc":"Which preset was used, if any."},{"name":"Position","lua_type":"Vector3","desc":"World-space origin of the emission."},{"name":"Source","lua_type":"Instance?","desc":"The Instance that produced this sound (excluded from occlusion raycasts)."},{"name":"Intensity","lua_type":"number","desc":"Source intensity at origin, 0\u2013100 scale."},{"name":"Radius","lua_type":"number","desc":"Maximum propagation distance in studs."},{"name":"Duration","lua_type":"number","desc":"Physical duration in seconds (0.05 for gunshots, 60 for vending machine)."},{"name":"Frequency","lua_type":"string","desc":"`\\"low\\"` | `\\"mid\\"` | `\\"high\\"` \u2014 affects material absorption."},{"name":"EmittedAt","lua_type":"number","desc":"`os.clock()` when emitted."},{"name":"ExpiresAt","lua_type":"number","desc":"`EmittedAt + Duration + 0.6` (the 0.6s decay window)."},{"name":"Tag","lua_type":"string?","desc":"External metadata. `\\"Gunshot_Rifle\\"`, `\\"Footstep_Walk\\"`, etc."}],"source":{"line":95,"path":"docs/SoundTypes.lua"}},{"name":"SoundStimulus","desc":"The result of a propagation query at a listener\'s position. Returned\\nby [Resonix:QueryPosition] and [Resonix:QueryStrongest].","fields":[{"name":"Emission","lua_type":"SoundEmission","desc":"Original emission data."},{"name":"EffectiveIntensity","lua_type":"number","desc":"Computed intensity at listener position, 0\u2013100."},{"name":"Direction","lua_type":"Vector3","desc":"Unit vector from listener toward the source."},{"name":"Distance","lua_type":"number","desc":"Straight-line distance from source to listener in studs."},{"name":"OcclusionFactor","lua_type":"number","desc":"Beer-Lambert transmission factor: 1.0 = clear path, ~0 = heavily blocked."}],"source":{"line":109,"path":"docs/SoundTypes.lua"}},{"name":"EmissionPreset","desc":"A template for creating emissions. Registered via [Resonix:RegisterPreset]\\nand used by [Resonix:EmitPreset].","fields":[{"name":"Intensity","lua_type":"number","desc":"Source intensity at origin, 0\u2013100 scale."},{"name":"Radius","lua_type":"number","desc":"Maximum propagation distance in studs."},{"name":"Duration","lua_type":"number","desc":"Physical duration in seconds."},{"name":"Frequency","lua_type":"string","desc":"`\\"low\\"` | `\\"mid\\"` | `\\"high\\"`."},{"name":"DefaultTag","lua_type":"string?","desc":"Default `Tag` value applied to emissions from this preset."}],"source":{"line":123,"path":"docs/SoundTypes.lua"}},{"name":"QueryResult","desc":"Array of [SoundStimulus] returned by [Resonix:QueryPosition]. Sorted\\ndescending by `EffectiveIntensity` \u2014 index `[1]` is always the loudest.","lua_type":"{ SoundStimulus }","source":{"line":131,"path":"docs/SoundTypes.lua"}}],"name":"SoundTypes","desc":"All type definitions and enum constants for Resonix.\\n\\nSeparated into their own module so every layer can import types without\\ncreating circular dependencies. These types reflect physical acoustic\\nconcepts only \u2014 intensity, radius, frequency, material \u2014 not game-specific\\ndomain logic.\\n\\nThe `Tag` field on [SoundEmission] is the one exception: it carries\\nexternal metadata that the sound system stores but never reads. Callers\\nuse it to classify stimuli after querying.","source":{"line":15,"path":"docs/SoundTypes.lua"}}')}}]);